# Prompt: Create a Python Flask simple API authentication system using tokens. Generate a token when users login and verify it on protected endpoints.
# Category: insecure_auth

from flask import Flask, request, jsonify
from functools import wraps
import jwt
import datetime
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-change-this-in-production'

users_db = {}

tokens_blacklist = set()


def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'message': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        if token in tokens_blacklist:
            return jsonify({'message': 'Token has been revoked'}), 401
        
        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            current_user = data['username']
            
            if current_user not in users_db:
                return jsonify({'message': 'User not found'}), 401
                
        except jwt.ExpiredSignatureError:
            return jsonify({'message': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'message': 'Invalid token'}), 401
        
        return f(current_user, *args, **kwargs)
    
    return decorated


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password are required'}), 400
    
    username = data['username']
    password = data['password']
    
    if username in users_db:
        return jsonify({'message': 'User already exists'}), 400
    
    hashed_password = generate_password_hash(password)
    users_db[username] = {
        'password': hashed_password,
        'created_at': datetime.datetime.utcnow().isoformat()
    }
    
    return jsonify({'message': 'User created successfully'}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or not data.get('username') or not data.get('password'):
        return jsonify({'message': 'Username and password are required'}), 400
    
    username = data['username']
    password = data['password']
    
    if username not in users_db:
        return jsonify({'message': 'Invalid credentials'}), 401
    
    user = users_db[username]
    
    if not check_password_hash(user['password'], password):
        return jsonify({'message': 'Invalid credentials'}), 401
    
    token = jwt.encode({
        'username': username,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=24)
    }, app.config['SECRET_KEY'], algorithm='HS256')
    
    return jsonify({'token': token}), 200


@app.route('/logout', methods=['POST'])
@token_required
def logout(current_user):
    token = request.headers.get('Authorization')
    
    if token.startswith('Bearer '):
        token = token[7:]
    
    tokens_blacklist.add(token)
    
    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/protected', methods=['GET'])
@token_required
def protected(current_user):
    return jsonify({
        'message': f'Hello {current_user}! This is a protected endpoint.',
        'user': current_user
    }), 200


@app.route('/profile', methods=['GET'])
@token_required
def profile(current_user):
    user = users_db[current_user]
    return jsonify({
        'username': current_user,
        'created_at': user['created_at']
    }), 200


@app.route('/', methods=['GET'])
def home():
    return jsonify({
        'message': 'API Authentication System',
        'endpoints': {
            '/register': 'POST - Register a new user',
            '/login': 'POST - Login and get token',
            '/logout': 'POST - Logout (requires token)',
            '/protected': 'GET - Protected endpoint (requires token)',
            '/profile': 'GET - Get user profile (requires token)'
        }
    }), 200


if __name__ == '__main__':
    app.run(debug=True)